#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n, L, R;
int ans;
int s[100005];
int a[100005];
vector < int > num;
int c[300005];
int lowbit( int x ) {
	return x & ( -x );
}
void update( int i , int k ) {
	for( ; i <= num.size() ; i += lowbit( i ) ) {
		c[i] += k;
	}
}
int getsum( int i ) {
	int ans = 0;
	for( ; i > 0 ; i -= lowbit( i ) ) {
		ans += c[i];
	}
	return ans;
}
int query (int l, int r) {
	if (l > r) {
		return 0;
	} else {
		return getsum(r) - getsum(l - 1);
	}
}
int fid (int x) {
	return lower_bound (num.begin(), num.end(), x) - num.begin() + 1;
}
signed main() {
	cin >> n >> L >> R;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		s[i] = s[i - 1] + a[i];
	}
	for (int i = 0; i <= n; i++) {
		num.push_back(s[i]);
		num.push_back(s[i] - L);
		num.push_back(s[i] - R);
	}
	sort (num.begin(), num.end());
	num.erase (unique (num.begin(), num.end()), num.end());
	update (fid(s[0]), 1);
	for (int i = 1; i <= n; i++) {
		int Left = fid (s[i] - R);
		int Right = fid (s[i] - L);
		ans += query (Left, Right);
		update (fid (s[i]), 1);
	}
	cout << ans;
	return 0;
}
